interface LineItem {
  description: string;
  quantity: number;
  unitPrice: number;
  taxRate: number;
  discount?: { type: 'percentage' | 'fixed'; value: number };
}

interface InvoiceResult {
  lines: Array<{
    subtotal: number;
    discountAmount: number;
    taxableAmount: number;
    taxAmount: number;
    total: number;
  }>;
  subtotal: number;
  totalDiscount: number;
  totalTax: number;
  grandTotal: number;
}

function calculateInvoice(items: LineItem[]): InvoiceResult {
  const lines = items.map(item => {
    // Calculate subtotal: quantity * unitPrice, rounded to 2 decimals
    const subtotal = Math.round(item.quantity * item.unitPrice * 100) / 100;

    // Calculate discount amount
    let discountAmount = 0;
    if (item.discount) {
      if (item.discount.type === 'percentage') {
        // For percentage discounts, calculate as percentage of subtotal then cap at subtotal
        discountAmount = Math.round(Math.min(item.discount.value * subtotal, subtotal) * 100) / 100;
      } else {
        // For fixed discounts, subtract the value but don't exceed subtotal
        discountAmount = Math.round(Math.min(item.discount.value, subtotal) * 100) / 100;
      }
    }

    // Calculate taxable amount after discount
    const taxableAmount = Math.round((subtotal - discountAmount) * 100) / 100;

    // Calculate tax on the taxable amount only
    const taxAmount = Math.round(taxableAmount * item.taxRate * 100) / 100;

    // Total for this line
    const total = Math.round((taxableAmount + taxAmount) * 100) / 100;

    return {
      subtotal,
      discountAmount,
      taxableAmount,
      taxAmount,
      total
    };
  });

